sql.where:
deleted_at is null

  and (lower(ticket_no) like #{keyword} or lower(report_url) like #{keyword} or lower(email) like #{keyword})

and report_type = #{reportType}
and status = #{status}
and feedback_time >= #{start}
and feedback_time < #{end}

mapper.select:
select * from feedbacks

order by feedback_time desc, id desc
limit #{limit} offset #{offset}
